/// Configure all HTTP routes for this module using Axum and BackboneCrudHandler.
///
/// Each entity gets 12 standard Backbone CRUD endpoints:
/// 1. GET /api/v1/{collection} - List with pagination
/// 2. POST /api/v1/{collection} - Create
/// 3. GET /api/v1/{collection}/:id - Get by ID
/// 4. PUT /api/v1/{collection}/:id - Full update
/// 5. PATCH /api/v1/{collection}/:id - Partial update
/// 6. DELETE /api/v1/{collection}/:id - Soft delete
/// 7. POST /api/v1/{collection}/bulk - Bulk create
/// 8. POST /api/v1/{collection}/upsert - Upsert
/// 9. GET /api/v1/{collection}/trash - List deleted
/// 10. POST /api/v1/{collection}/:id/restore - Restore
/// 11. DELETE /api/v1/{collection}/empty - Empty trash
/// 12. GET /api/v1/{collection}/:id/deleted - Get deleted by ID
pub fn configure_routes(services: HttpServices) -> Router {
    Router::new()
        // Account routes (12 Backbone endpoints)
        .merge(create_account_routes(services.account))
        // AccountingPost routes (12 Backbone endpoints)
        .merge(create_accounting_post_routes(services.accounting_post))
        // FinancialStatement routes (12 Backbone endpoints)
        .merge(create_financial_statement_routes(services.financial_statement))
        // FiscalPeriod routes (12 Backbone endpoints)
        .merge(create_fiscal_period_routes(services.fiscal_period))
        // Journal routes (12 Backbone endpoints)
        .merge(create_journal_routes(services.journal))
        // JournalLine routes (12 Backbone endpoints)
        .merge(create_journal_line_routes(services.journal_line))
        // Ledger routes (12 Backbone endpoints)
        .merge(create_ledger_routes(services.ledger))
        // Reconciliation routes (12 Backbone endpoints)
        .merge(create_reconciliation_routes(services.reconciliation))
        // ReconciliationItem routes (12 Backbone endpoints)
        .merge(create_reconciliation_item_routes(services.reconciliation_item))
}

